// Take only first 3 stale posts per run (API budget control)
const items = $input.all();
const posts = Array.isArray(items[0]?.json) ? items[0].json : items.map(i => i.json);
const limited = posts.slice(0, 3);
if (limited.length === 0) {
  return [{ json: { _empty: true, total_found: 0 } }];
}
return limited.map(p => ({ json: p }));

// Pass through existing content — already fetched in step 2
const item = $input.first().json;
if (item._empty) {
  return [{ json: { _empty: true, total_found: 0 } }];
}
return [{ json: { id: item.id, title: item.title, slug: item.slug, content: item.content, meta_description: item.meta_description || '' } }];

