// Quality Gate: extract refreshed content, check word count >= 800
const input = $input.first().json;
const post = $('Read Existing Content').first().json;

if (post._empty) {
  return [{ json: { _skip: true, reason: 'no_posts', id: null, slug: null } }];
}

const text = input.content?.[0]?.text || '';
if (!text) {
  return [{ json: { _skip: true, reason: 'api_error', id: post.id, slug: post.slug } }];
}

// Split meta description from content
const lines = text.split('\n');
let metaDesc = '';
let contentLines = [];
for (const line of lines) {
  if (line.startsWith('META_DESC:')) {
    metaDesc = line.replace('META_DESC:', '').trim().substring(0, 160);
  } else {
    contentLines.push(line);
  }
}
const refreshedContent = contentLines.join('\n').trim();
const wordCount = refreshedContent.split(/\s+/).length;

if (wordCount < 800) {
  return [{ json: { _skip: true, reason: 'too_short', word_count: wordCount, id: post.id, slug: post.slug } }];
}

return [{ json: {
  _skip: false,
  id: post.id,
  slug: post.slug,
  title: post.title,
  refreshed_content: refreshedContent,
  meta_description: metaDesc || post.meta_description,
  word_count: wordCount
} }];

